#!/usr/bin/env python3
"""Analyze 281-byte HID reports to find bytes that change during brightness adjustment."""

import sys

# All HID reports from the capture (frame_number, time, hex_data)
reports_raw = """45	1.243624	
113	3.783732	
131	4.322690	
169	5.837413	
181	6.346602	
241	7.870724	
261	8.378613	
279	8.907610	
309	9.913611	
321	10.422114	
333	10.930686	
381	12.496001	
391	12.963700	"""

reports = []
for line in reports_raw.strip().split('\n'):
    parts = line.strip().split('\t')
    frame = int(parts[0])
    time = float(parts[1])
    data = bytes.fromhex(parts[2])
    reports.append((frame, time, data))

print(f"Total reports: {len(reports)}")
print(f"Report length: {len(reports[0][2])} bytes")
print()

# Find bytes that change across reports
print("=== BYTES THAT CHANGE ACROSS ALL REPORTS ===")
first = reports[0][2]
for offset in range(len(first)):
    values = set()
    for frame, time, data in reports:
        if offset < len(data):
            values.add(data[offset])
    if len(values) > 1:
        print(f"  Offset 0x{offset:02X} ({offset:3d}): values = {[f'0x{v:02x}' for v in sorted(values)]}")
        for frame, time, data in reports:
            if offset < len(data):
                print(f"    Frame {frame:3d} t={time:6.2f}s: 0x{data[offset]:02x} ({data[offset]:3d})")

print()
print("=== REPORT CLASSIFICATION BY FIRST FEW BYTES ===")
# The first byte seems to be a report type
for frame, time, data in reports:
    # Look at key bytes
    b4 = data[4] if len(data) > 4 else 0
    b5 = data[5] if len(data) > 5 else 0
    b6 = data[6] if len(data) > 6 else 0
    b7 = data[7] if len(data) > 7 else 0
    print(f"  Frame {frame:3d} t={time:6.2f}s: bytes[4:8] = {data[4:8].hex()} bytes[8:12] = {data[8:12].hex()}")

# Try to find brightness-like values (0-100 range)
print()
print("=== LOOKING FOR BRIGHTNESS-LIKE VALUES (0-100 in changing bytes) ===")
for frame, time, data in reports:
    changing_offsets = []
    for offset in range(len(data)):
        values = set()
        for f2, t2, d2 in reports:
            if offset < len(d2):
                values.add(d2[offset])
        if len(values) > 1 and offset < len(data):
            changing_offsets.append(offset)
    
    # Show the values at changing offsets for this frame
    vals = {}
    for off in changing_offsets:
        vals[off] = data[off]
    
    # Print compact
    print(f"  Frame {frame:3d} t={time:6.2f}s:", end="")
    for off in sorted(changing_offsets):
        print(f" [{off:3d}]=0x{data[off]:02x}({data[off]:3d})", end="")
    print()

# Look at the second half of the report for patterns
print()
print("=== LOOK AT BYTES 172+ (tail section) ===")
for frame, time, data in reports:
    print(f"  Frame {frame:3d} t={time:6.2f}s: bytes[172:184] = {data[172:184].hex()} bytes[184:196] = {data[184:196].hex()}")
